import React, { useState, useEffect, useRef } from "react";
import { useTranslation } from 'react-i18next';
import api from "../api";
import "./Profile.css";
import { User, Mail, Shield, ShieldCheck, Phone, MapPin, Edit3, Save, CheckCircle, AlertTriangle, Info, Lock } from "lucide-react";

function Toast({ message, type, onDone }) {
  useEffect(() => {
    const t = setTimeout(onDone, 3000);
    return () => clearTimeout(t);
  }, [onDone]);
  const Icon = type === 'success' ? CheckCircle : type === 'error' ? AlertTriangle : Info;
  return (
    <div className={`toast ${type}`} style={{
      position: 'fixed', bottom: 24, left: '50%', transform: 'translateX(-50%)',
      zIndex: 9999, background: 'var(--card-bg)', borderLeft: `4px solid ${type === 'success' ? '#10b981' : '#ef4444'}`,
      padding: '12px 20px', borderRadius: 12, boxShadow: '0 10px 25px rgba(0,0,0,0.1)',
      display: 'flex', alignItems: 'center', gap: 12, color: 'var(--text)', animation: 'slideUp 0.3s ease-out'
    }}>
      <Icon size={18} color={type === 'success' ? '#10b981' : '#ef4444'} />
      <span style={{ fontSize: '0.9rem', fontWeight: 600 }}>{message}</span>
    </div>
  );
}

export default function Profile() {
  const { t } = useTranslation();
  const [user, setUser] = useState(JSON.parse(localStorage.getItem("user")));
  const [twofa, setTwofa] = useState(false);
  const [loading, setLoading] = useState(false);
  const [toasts, setToasts] = useState([]);
  const toastIdRef = useRef(0);
  const addToast = (message, type = 'info') => {
    const id = ++toastIdRef.current;
    setToasts((prev) => [...prev, { id, message, type }]);
  };
  const removeToast = (id) => setToasts((prev) => prev.filter((t) => t.id !== id));


  useEffect(() => {
    // Fetch latest user data including 2FA status
    const fetchUserData = async () => {
      try {
        const res = await api.get('/api/user/profile');
        if (res.data) {
          setTwofa(!!res.data.twofa_enabled);
        }
      } catch (err) {
        console.error("Failed to fetch user profile", err);
      }
    };
    if (user?.id) fetchUserData();
  }, [user?.id]);

  const handleToggle2FA = async () => {
    setLoading(true);
    try {
      const res = await api.post("/api/user/2fa", { enable: !twofa });
      setTwofa(res.data.twofa);
      addToast(`2-Step Authentication has been ${res.data.twofa ? "Enabled" : "Disabled"}.`, "success");
    } catch (err) {
      addToast("Failed to toggle 2FA", "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="profile-container" style={{ minHeight: '100vh', background: 'var(--background)', padding: '2rem var(--container-padding)' }}>
      {toasts.map(t => <Toast key={t.id} message={t.message} type={t.type} onDone={() => removeToast(t.id)} />)}
      <div className="profile-card" style={{ maxWidth: 780, margin: '0 auto' }}>
        <div className="profile-header">
          <div className="profile-avatar-wrapper">
            {user?.name?.charAt(0).toUpperCase() || <User size={40} />}
          </div>
          <h2>{user?.name}</h2>
          <p>{user?.role?.toUpperCase()} {t('nav_dashboard')}</p>
        </div>

        <div className="profile-content">
          <div className="profile-section">
            <h3><User size={18} /> {t('prof_details')}</h3>
            <div className="info-grid">
              <div className="info-item">
                <label>{t('prof_name')}</label>
                <span>{user?.name}</span>
              </div>
              <div className="info-item">
                <label>{t('reg_email')}</label>
                <span>{user?.email}</span>
              </div>
              <div className="info-item">
                <label>{t('tab_verif')}</label>
                <span style={{ color: user?.approval_status === 'approved' ? '#10b981' : '#f59e0b' }}>
                  {user?.approval_status?.toUpperCase() || 'ACTIVE'}
                </span>
              </div>
            </div>
          </div>

          <div className="profile-section">
            <h3><Shield size={18} /> {t('sec_title')}</h3>
            <div className="settings-card">
              <div className="settings-info">
                <h4>{t('sec_2fa')}</h4>
                <p>{t('sec_2fa_desc')}</p>
              </div>
              <label className="switch">
                <input 
                  type="checkbox" 
                  checked={twofa} 
                  onChange={handleToggle2FA} 
                  disabled={loading}
                />
                <span className="slider"></span>
              </label>
            </div>
          </div>

          <div className="profile-actions">
            <button className="btn-secondary">{t('change_pass')}</button>
            <button className="btn-primary"><Edit3 size={18} /> {t('prof_save')}</button>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from "react";
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import api from "../api";
import { useTheme } from "../component/ThemeContext";
import { User, Phone, Image, Moon, Sun, ShieldCheck, Trash2, LogOut, Info, CheckCircle, AlertTriangle, Lock, Eye, EyeOff, Settings } from 'lucide-react';
import './DriverDashboard.css';

function Toast({ message, type, onDone }) {
  useEffect(() => {
    const t = setTimeout(onDone, 3000);
    return () => clearTimeout(t);
  }, []);
  const Icon = type === 'success' ? CheckCircle : type === 'error' ? AlertTriangle : Info;
  return (
    <div className={`toast ${type}`}>
      <Icon size={18} /> {message}
    </div>
  );
}

export default function Setting() {
  const { t } = useTranslation();
  const { darkMode, toggleDarkMode } = useTheme();
  const [user, setUser] = useState(() => {
    try { return JSON.parse(localStorage.getItem('user') || 'null') } catch (e) { return null }
  });
  const [name, setName] = useState(user?.name || '');
  const [phone, setPhone] = useState(user?.phone || '');
  const [avatarData, setAvatarData] = useState(user?.avatar || '');
  const [twofa, setTwofa] = useState(user?.twofa_enabled || false);
  const [esewaLinked, setEsewaLinked] = useState(localStorage.getItem(`esewa_${user?.email}`) === 'true');
  const [saving, setSaving] = useState(false);
  const [toasts, setToasts] = useState([]);
  const [showPassword, setShowPassword] = useState(false);
  const [passForm, setPassForm] = useState({ current: '', new: '', confirm: '' });
  const [changingPass, setChangingPass] = useState(false);
  const navigate = useNavigate();

  const toastIdRef = React.useRef(0);
  const addToast = (message, type = 'info') => {
    const id = ++toastIdRef.current;
    setToasts((prev) => [...prev, { id, message, type }]);
  };
  const removeToast = (id) => setToasts((prev) => prev.filter((t) => t.id !== id));

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) return;
    // best-effort fetch to get current true 2fa state
    api.post('/api/user/2fa', { enable: twofa }, { headers: { 'x-auth-token': token } })
       .then((res) => setTwofa(res.data.twofa))
       .catch(() => {});
  }, []);



  function onFileChange(e) {
    const f = e.target.files && e.target.files[0];
    if (!f) return;
    const reader = new FileReader();
    reader.onload = () => setAvatarData(reader.result);
    reader.readAsDataURL(f);
  }

  async function saveProfile() {
    const token = localStorage.getItem('token');
    if (!token) return addToast('Please login', 'error');
    setSaving(true);
    try {
      const body = { name, phone, avatar: avatarData };
      await api.post('/api/user/update', body, { headers: { 'x-auth-token': token } });
      const updated = { ...(user || {}), name, phone, avatar: avatarData };
      localStorage.setItem('user', JSON.stringify(updated));
      setUser(updated);
      addToast('Profile updated successfully!', 'success');
    } catch (e) {
      console.error(e);
      addToast('Failed to update profile', 'error');
    }
    setSaving(false);
  }

  async function toggle2fa() {
    const token = localStorage.getItem('token');
    if (!token) return addToast('Login required', 'error');
    try {
      const res = await api.post('/api/user/2fa', { enable: !twofa }, { headers: { 'x-auth-token': token } });
      setTwofa(res.data.twofa);
      const updated = { ...(user || {}), twofa_enabled: res.data.twofa };
      localStorage.setItem('user', JSON.stringify(updated));
      setUser(updated);
      addToast(`Two-factor auth ${res.data.twofa ? 'enabled' : 'disabled'}`, 'success');
    } catch (e) {
      console.error(e);
      addToast('Failed to update 2FA', 'error');
    }
  }

  function toggleEsewa() {
    const newVal = !esewaLinked;
    setEsewaLinked(newVal);
    localStorage.setItem(`esewa_${user?.email}`, newVal ? 'true' : 'false');
    addToast(newVal ? 'eSewa account linked securely!' : 'eSewa account unlinked', 'success');
  }

  async function deleteAccount() {
    if (!confirm('Delete your account? This is irreversible and all your data will be permanently wiped.')) return;
    const token = localStorage.getItem('token');
    if (!token) return;
    try {
      await api.delete('/api/user', { headers: { 'x-auth-token': token } });
      localStorage.clear();
      try { socket.disconnect(); } catch (e) {}
      navigate('/');
    } catch (e) {
      console.error(e);
      addToast('Failed to delete account', 'error');
    }
  }

  function logout() {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    try { socket.disconnect(); } catch (e) {}
    navigate('/login');
  }

  async function changePassword() {
    if (!passForm.current || !passForm.new || !passForm.confirm) return addToast('Please fill all password fields', 'error');
    if (passForm.new !== passForm.confirm) return addToast('New passwords do not match', 'error');
    if (passForm.new.length < 6) return addToast('Password must be at least 6 characters', 'error');

    const token = localStorage.getItem('token');
    setChangingPass(true);
    try {
      await api.post('/api/user/change-password', {
        currentPassword: passForm.current,
        newPassword: passForm.new
      }, { headers: { 'x-auth-token': token } });
      addToast('Password changed successfully!', 'success');
      setPassForm({ current: '', new: '', confirm: '' });
      setShowPassword(false);
    } catch (e) {
      addToast(e.response?.data || 'Failed to change password', 'error');
    }
    setChangingPass(false);
  }

  return (
