          </div>

          <div className="glass-card">
            <h2 className="glass-card-title"><ShieldCheck size={18} /> {t('sec_title')}</h2>
            <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: 16 }}>
