              <div>
                <div style={{ fontWeight: 600, fontSize: '0.9rem', color: 'var(--text-primary)' }}>{t('sec_2fa')}</div>
                <div style={{ fontSize: '0.75rem', color: twofa ? 'var(--green)' : 'var(--text-muted)', marginTop: 4, fontWeight: 500 }}>
